CustomField.formula:
/* Create an opening border of grey on the far left, 18 px high and 2 px wide */
IMAGE("/resource/1760612208000/GreyProgress?", "Grey", 18, 2)
&
/* Create a green bar to represent completeness of the task, 18 px high and of a width of the % field value (1% = 1px) */
IMAGE("/resource/1752501704000/GreenProgress?", "GreenProgress", 18,  pro_Lease_Documentation_Approval_per__c * 100)
&
/* Create a grey bar to represent incompleteness of the task, 18 px high and of a width controlled by 1-% field value */
IMAGE("/resource/1760612208000/GreyProgress?", "Grey", 18, (1 - pro_Lease_Documentation_Approval_per__c ) * 100)
&
/* Create a closing border of grey on the far right, 18 pixels high and 2 px wide */ IMAGE("/resource/1760612208000/GreyProgress?", "Grey", 18, 2)
